-- Step 1: Get MeasureForge AI company ID
-- SELECT id, name FROM companies WHERE name LIKE '%MeasureForge%';

-- ============================================================
-- IMPORTANT: Schema constraints for this table:
-- - agents table has NO unique constraint on 'name'
-- - Model config is stored in adapter_config JSONB field
-- - API keys are stored in agent_api_keys table with SHA256 hashes
-- - Activity logs track all agent creation events
