-- ============================================================
-- AGENT REGISTRATION (Idempotent - uses NOT EXISTS check)
-- ============================================================

-- 1. Sage Weaver - Procurement Classifier
INSERT INTO agents (
  id,
  company_id,
  name,
  role,
  title,
  icon,
  status,
  reports_to,
  capabilities,
  adapter_type,
  runtime_config,
  adapter_config,
  created_at,
  updated_at
)
SELECT
  gen_random_uuid(),
  c.id,
  'Sage Weaver',
  'specialist',
  'Procurement Classifier - Builder',
  '🧙',
  'active',
   (SELECT id FROM agents WHERE name = 'measureforge-ai-measurement-director' AND company_id = c.id),
  '["cad-measurement-interpretation", "procurement-classification-rules", "material-type-recognition", "trade-specialization-knowledge"]',
  'hermes_local',
  '{"run_heartbeat": 300}'::jsonb,
  '{
    "adapter": "hermes_local",
    "model": "anthropic/claude-opus-4.6",
    "temperature": 0.7,
    "max_tokens": 4096,
    "environment": {
      "OPENROUTER_API_KEY": "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"
    },
    "skills": ["cad-measurement-interpretation", "procurement-classification-rules", "material-type-recognition", "trade-specialization-knowledge"]
  }'::jsonb,
  NOW(),
  NOW()
FROM companies c
WHERE c.name = 'MeasureForge AI'
  AND NOT EXISTS (
    SELECT 1 FROM agents a
    WHERE a.name = 'Sage Weaver'
      AND a.company_id = c.id
  );

