-- ============================================================
-- API KEY GENERATION FOR ALL AGENTS
-- ============================================================

-- Generate API keys for each agent (this would be done programmatically in production)
-- For now, we'll use placeholder keys that would be generated securely

INSERT INTO agent_api_keys (
  id,
  agent_id,
  company_id,
  name,
  api_key,
  key_hash,
  created_at
)
SELECT
  gen_random_uuid(),
  a.id,
  a.company_id,
  a.name || ' API Key',
  'PLACEHOLDER_KEY_SET_MANUALLY',
  encode(sha256(('pcak_' || gen_random_uuid()::text)::bytea), 'hex'),
  NOW()
FROM agents a
WHERE a.company_id = (SELECT id FROM companies WHERE name = 'MeasureForge AI')
  AND a.name IN ('Sage Weaver', 'Forge Master', 'Resource Baron', 'Service Sage', 'Task Titan', 'Match Maker', 'Candy Connector', 'Budget Guardian', 'Gate Keeper')
  AND NOT EXISTS (
    SELECT 1 FROM agent_api_keys ak WHERE ak.agent_id = a.id
  );

