-- ============================================================
-- ACTIVITY LOG ENTRIES
-- ============================================================

INSERT INTO activity_log (
  id,
  company_id,
  agent_id,
  action,
  details,
  created_at
)
SELECT
  gen_random_uuid(),
  a.company_id,
  a.id,
  'agent_created',
  jsonb_build_object(
    'agent_name', a.name,
    'agent_title', a.title,
    'created_by', 'Nimbus - Supabase Database Specialist',
    'purpose', 'Builder procurement segregation workflows'
  ),
  NOW()
FROM agents a
WHERE a.company_id = (SELECT id FROM companies WHERE name = 'MeasureForge AI')
  AND a.name IN ('Sage Weaver', 'Forge Master', 'Resource Baron', 'Service Sage', 'Task Titan', 'Match Maker', 'Candy Connector', 'Budget Guardian', 'Gate Keeper');

